// find-email: find all email addresses in a string using regexped WASM.
// stub.ts is auto-generated by: regexped generate --config=regexped.yaml
import {
  find_email_reset,
  find_email_next,
  find_email_group,
  find_email_get_user,
  find_email_get_domain,
} from "./stub";

function slice(buf: ArrayBuffer, packed: i64): string {
  const start = i32(<u64>packed >> 32);
  const end   = i32(<u32>packed);
  return String.UTF8.decodeUnsafe(changetype<usize>(buf) + <usize>start, <usize>(end - start), false);
}

function findEmails(text: string): void {
  console.log("input: " + text);
  const buf = String.UTF8.encode(text);
  find_email_reset();
  let found = false;
  while (find_email_next(buf)) {
    found = true;
    console.log("  email:  " + slice(buf, find_email_group(0)));
    console.log("    user:   " + slice(buf, find_email_get_user()));
    console.log("    domain: " + slice(buf, find_email_get_domain()));
  }
  if (!found) {
    console.log("  (no emails found)");
  }
}

findEmails("Contact alice@example.com or bob@company.org for details.");
findEmails("reach us at support@open-source.io and sales@widgets.co.uk");
findEmails("no emails here");
